// Crear un archivo de registro si no existe
const logFile = createWriteStream(logFilePath, { flags: 'a' });

// Función para registrar eventos de teclado
function logKeyboardEvent(event) {
    logFile.write(`[${new Date().toISOString()}] ${event.type} ${event.key}\n`);
}

// Agregar un evento de teclado al escuchar eventos de teclado
document.addEventListener('keydown', logKeyboardEvent);
